// src/views/WaiterProfile.js
import React, { useState, useEffect } from "react";
import { useParams, useLocation } from "react-router-dom";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";
import SocialFooter from "components/Common/socialFooter";
import CommentSection from "components/Common/commentSection";

export default function WaiterProfile() {
  const { id } = useParams();
  const location = useLocation();
  const fromMenu = location.state?.fromMenu || false;
  const waiterInfoFromMenu = location.state?.waiterInfo || null;
  
  const [waiterInfo, setWaiterInfo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showCommentModal, setShowCommentModal] = useState(false);
  const [newComment, setNewComment] = useState({ rating: 5, comment: "" });
  
  // بيانات تجريبية للنادلين
  const waitersData = {
    5: {
      id: 5,
      name: "Karim El Fassi",
      role: "Serveur en chef",
      profileImage: "https://randomuser.me/api/portraits/men/45.jpg",
      coverImage: "https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=1200",
      location: "Casablanca, Maroc",
      rating: 4.9,
      experience: "8 ans d'expérience",
      skills: ["Service client", "Gestion des commandes", "Travail d'équipe", "Multilingue"],
      bio: "Passionné par le service client, je m'assure que chaque client vive une expérience inoubliable dans notre restaurant.",
      status: "active",
      email: "karim.elfassi@restaurant.com",
      phone: "+212 6 12 34 56 78",
      languages: ["Français", "Arabe", "Anglais"],
      groupName: "Groupe 1",
      restaurantName: "Restaurant Andalous",
      comments: [
        { id: 1, user: "Client anonyme", rating: 5, comment: "Excellent service !", date: "2024-03-15" },
        { id: 2, user: "Client anonyme", rating: 4, comment: "Très professionnel", date: "2024-03-10" }
      ]
    }
  };
  
  useEffect(() => {
    if (fromMenu && waiterInfoFromMenu) {
      setWaiterInfo(waiterInfoFromMenu);
      setLoading(false);
    } else if (id && waitersData[id]) {
      setWaiterInfo(waitersData[id]);
      setLoading(false);
    } else {
      setTimeout(() => {
        setWaiterInfo(waitersData[5]);
        setLoading(false);
      }, 500);
    }
  }, [id, fromMenu, waiterInfoFromMenu]);
  
  const handleAddComment = () => {
    if (!newComment.comment.trim()) {
      alert("⚠️ Veuillez écrire un commentaire");
      return;
    }
    
    const comment = {
      id: Date.now(),
      user: "Client",
      rating: newComment.rating,
      comment: newComment.comment,
      date: new Date().toISOString().split('T')[0]
    };
    
    setWaiterInfo(prev => ({
      ...prev,
      comments: [comment, ...(prev?.comments || [])]
    }));
    
    setNewComment({ rating: 5, comment: "" });
    setShowCommentModal(false);
    alert("✅ Commentaire ajouté avec succès !");
  };
  
  const style = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    @keyframes borderPulse {
      0%, 100% { opacity: 0.6; filter: blur(8px); }
      50% { opacity: 1; filter: blur(12px); }
    }
    
    @keyframes gradient-border {
      0% { background-position: 0% 0%; }
      50% { background-position: 400% 0%; }
      100% { background-position: 0% 0%; }
    }
    
    .waiter-profile-container {
      min-height: 100vh;
      width: 100%;
      background: #0a0a0a;
      position: relative;
      overflow-x: hidden;
    }
    
    .bg-gradient {
      position: fixed;
      inset: 0;
      background: radial-gradient(ellipse at 50% 30%, 
        #19022a 0%,
        #1c084b 30%,
        #1a0b2e 60%,
        #0a0a0a 85%,
        #050505 100%
      );
      z-index: 0;
    }
    
    .hero-image {
      position: absolute;
      top: 0;
      width: 100%;
      height: 100%;
      background-position: center 30%;
      background-size: cover;
      filter: brightness(0.85) contrast(1.05);
    }
    
    .hero-overlay {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.05) 30%, rgba(0,0,0,0) 50%, rgba(26,26,58,0.6) 100%);
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(16px);
      border-radius: 28px;
      border: 1px solid rgba(255, 255, 255, 0.25);
      box-shadow: 0 20px 40px rgba(0, 0, 0, 0.2);
    }
    
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(5px);
    }
    
    .gradient-border-box .content {
      width: calc(100% - 4px);
      height: calc(100% - 4px);
      background-size: cover;
      background-position: center;
      border-radius: 50%;
      box-shadow: 0 0 30px rgba(0,0,0,0.3);
    }
    
    .profile-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 170px;
      height: 170px;
      background: radial-gradient(circle, rgba(34,197,94,0.3) 0%, rgba(34,197,94,0) 70%);
      border-radius: 50%;
      z-index: -1;
      animation: borderPulse 2s ease-in-out infinite;
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
      background: #22c55e;
      color: white;
    }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
      border: 1px solid rgba(34,197,94,0.4);
      backdrop-filter: blur(5px);
    }
    
    .info-card {
      background: rgba(255,255,255,0.08);
      backdrop-filter: blur(10px);
      border-radius: 20px;
      padding: 20px;
      margin-bottom: 20px;
      border: 1px solid rgba(34,197,94,0.2);
      transition: all 0.3s;
    }
    
    .info-card:hover {
      transform: translateY(-3px);
      border-color: rgba(34,197,94,0.5);
    }
    
    .info-title {
      font-size: 1.1rem;
      font-weight: bold;
      color: white;
      margin-bottom: 15px;
      display: flex;
      align-items: center;
      gap: 10px;
      border-bottom: 1px solid rgba(255,255,255,0.1);
      padding-bottom: 8px;
    }
    
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0,0,0,0.9);
      backdrop-filter: blur(10px);
      z-index: 1000;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 500px;
      width: 90%;
      border: 2px solid #22c55e;
    }
    
    .rating-star {
      font-size: 2rem;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .rating-star:hover {
      transform: scale(1.1);
    }
    
    @media (max-width: 768px) {
      .gradient-border-box {
        width: 120px;
        height: 120px;
        margin-top: -50px;
        margin-left: 0;
      }
    }
  `;

  if (loading) {
    return (
      <>
        <style>{style}</style>
        <Navbar />
        <div className="waiter-profile-container" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div className="bg-gradient"></div>
          <div style={{ textAlign: 'center', zIndex: 10, color: 'white' }}>
            <div className="spinner" style={{ width: '50px', height: '50px', border: '3px solid rgba(255,255,255,0.2)', borderTopColor: '#22c55e', borderRadius: '50%', animation: 'spin 1s linear infinite', margin: '0 auto 20px' }}></div>
            <p>Chargement du profil...</p>
          </div>
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
        <Footer />
      </>
    );
  }

  if (!waiterInfo) {
    return (
      <>
        <style>{style}</style>
        <Navbar />
        <div className="waiter-profile-container" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
          <div className="bg-gradient"></div>
          <div style={{ textAlign: 'center', zIndex: 10, color: 'white' }}>
            <h2>👨‍🍳 Serveur non trouvé</h2>
            <p>Le profil que vous recherchez n'existe pas.</p>
          </div>
        </div>
        <Footer />
      </>
    );
  }

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="waiter-profile-container">
        <div className="bg-gradient"></div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px", position: 'relative', overflow: 'hidden' }}>
            <div className="hero-image" style={{ backgroundImage: `url(${waiterInfo.coverImage})`, backgroundSize: 'cover', backgroundPosition: 'center 40%' }}></div>
            <div className="hero-overlay"></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="profile-image-wrapper" style={{ position: 'relative' }}>
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt={waiterInfo.name} src={waiterInfo.profileImage} className="content" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }} />
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-white">
                      {waiterInfo.name}
                      <span className="status-badge">👨‍🍳 Serveur</span>
                    </h3>
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {waiterInfo.location}
                    </div>
                    <div className="mb-2 text-gray-300 mt-10">
                      <i className="fas fa-briefcase mr-2 text-green-400"></i> {waiterInfo.role}
                    </div>
                    <div className="mb-2 text-gray-300">
                      <i className="fas fa-calendar-alt mr-2 text-green-400"></i> {waiterInfo.experience}
                    </div>
                    <div className="mb-2 text-gray-300">
                      <i className="fas fa-users mr-2 text-green-400"></i> Groupe : {waiterInfo.groupName}
                    </div>
                    <div className="mb-2 text-gray-300">
                      <i className="fas fa-utensils mr-2 text-green-400"></i> Restaurant : {waiterInfo.restaurantName}
                    </div>
                  </div>
                  
                  <div className="mt-8 py-4 border-t border-white/20">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{waiterInfo.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {waiterInfo.skills.map((skill, i) => (<span key={i} className="skill-tag">{skill}</span>))}
                        </div>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {waiterInfo.languages?.map((lang, i) => (<span key={i} className="skill-tag">🌐 {lang}</span>))}
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  {/* Section des commentaires (visible uniquement quand on vient du menu) */}
                  {fromMenu && (
                    <div className="mt-6">
                      <div className="info-card">
                        <div className="info-title">
                          <span>💬</span> Avis et commentaires
                        </div>
                        
                        <button 
                          onClick={() => setShowCommentModal(true)}
                          style={{
                            background: 'linear-gradient(135deg, #22c55e, #15803d)',
                            border: 'none',
                            padding: '10px 20px',
                            borderRadius: '25px',
                            color: 'white',
                            fontWeight: 'bold',
                            cursor: 'pointer',
                            marginBottom: '20px',
                            width: '100%'
                          }}
                        >
                          ✍️ Ajouter un commentaire
                        </button>
                        
                        <div style={{ maxHeight: '300px', overflowY: 'auto' }}>
                          {waiterInfo.comments?.length > 0 ? (
                            waiterInfo.comments.map(comment => (
                              <div key={comment.id} style={{
                                background: 'rgba(255,255,255,0.05)',
                                borderRadius: '15px',
                                padding: '12px',
                                marginBottom: '10px'
                              }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '5px' }}>
                                  <span style={{ fontWeight: 'bold', color: '#22c55e' }}>{comment.user}</span>
                                  <div style={{ display: 'flex', gap: '2px' }}>
                                    {[1,2,3,4,5].map(star => (
                                      <span key={star} style={{ color: star <= comment.rating ? '#ffc107' : 'rgba(255,255,255,0.2)' }}>★</span>
                                    ))}
                                  </div>
                                </div>
                                <p style={{ color: 'rgba(255,255,255,0.8)', fontSize: '0.85rem', marginBottom: '5px' }}>{comment.comment}</p>
                                <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.7rem' }}>{comment.date}</span>
                              </div>
                            ))
                          ) : (
                            <p style={{ textAlign: 'center', color: 'rgba(255,255,255,0.5)', padding: '20px' }}>
                              Aucun commentaire pour le moment
                            </p>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                  
                  <div className="mt-6">
                    <div className="info-card">
                      <div className="info-title"><span>📞</span> Contact</div>
                      <div style={{ color: 'rgba(255,255,255,0.7)' }}>
                        <p><strong>📧 Email :</strong> {waiterInfo.email}</p>
                        <p><strong>📱 Téléphone :</strong> {waiterInfo.phone}</p>
                      </div>
                    </div>
                  </div>
                  
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* Modal d'ajout de commentaire */}
      {showCommentModal && (
        <div className="modal-overlay" onClick={() => setShowCommentModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2 style={{ color: 'white', marginBottom: '20px', textAlign: 'center' }}>✍️ Ajouter un avis</h2>
            
            <div style={{ textAlign: 'center', marginBottom: '20px' }}>
              <label style={{ color: 'white', display: 'block', marginBottom: '10px' }}>Votre note :</label>
              <div style={{ display: 'flex', justifyContent: 'center', gap: '10px' }}>
                {[1,2,3,4,5].map(star => (
                  <span 
                    key={star}
                    className="rating-star"
                    onClick={() => setNewComment({...newComment, rating: star})}
                    style={{ 
                      color: star <= newComment.rating ? '#ffc107' : 'rgba(255,255,255,0.3)',
                      fontSize: '2rem',
                      cursor: 'pointer'
                    }}
                  >
                    ★
                  </span>
                ))}
              </div>
            </div>
            
            <div className="input-group" style={{ marginBottom: '20px' }}>
              <label style={{ color: 'white', display: 'block', marginBottom: '10px' }}>Votre commentaire :</label>
              <textarea 
                rows="4"
                value={newComment.comment}
                onChange={(e) => setNewComment({...newComment, comment: e.target.value})}
                placeholder="Partagez votre expérience..."
                style={{
                  width: '100%',
                  padding: '12px',
                  background: 'rgba(255,255,255,0.1)',
                  border: '1px solid rgba(34,197,94,0.3)',
                  borderRadius: '15px',
                  color: 'white',
                  fontSize: '0.9rem',
                  resize: 'vertical'
                }}
              />
            </div>
            
            <div style={{ display: 'flex', gap: '15px' }}>
              <button 
                onClick={handleAddComment}
                style={{
                  flex: 1,
                  background: 'linear-gradient(135deg, #22c55e, #15803d)',
                  border: 'none',
                  padding: '12px',
                  borderRadius: '25px',
                  color: 'white',
                  fontWeight: 'bold',
                  cursor: 'pointer'
                }}
              >
                💾 Envoyer
              </button>
              <button 
                onClick={() => setShowCommentModal(false)}
                style={{
                  flex: 1,
                  background: 'rgba(255,255,255,0.1)',
                  border: '1px solid rgba(255,255,255,0.2)',
                  padding: '12px',
                  borderRadius: '25px',
                  color: 'white',
                  cursor: 'pointer'
                }}
              >
                ❌ Annuler
              </button>
            </div>
          </div>
        </div>
      )}
      
      <SocialFooter socialLinks={{}} />
      <Footer />
    </>
  );
}
